15	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
16	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
17	 *
18	 */
19	/*
20	 *  simpleuart lightly modified by L. Doolittle from C. Wolf's original:
21	 *    cfg_divider is a direct input, rather than attaching to a host bus
22	 *    send_divcnt and recv_divcnt are now only 20 bits wide
23	 *    reg_dat_ names are shortened to b_
24	 *    actual data ports are now only 8 bits wide (not padded to 32)
25	 *    b_busy and b_dv are new outputs
26	 *    send_divcnt is now a down-counter with pipelined terminal count detect
27	 *
28	 *  Baud rate computation:
29	 *    One bit time is clk period * cfg_divider
30	 *    e.g., use cfg_divider = 13021 for 9600 baud with 125 MHz clk
31	 *    minimum valid value of cfg_divider is 2.
32	 */
33	
34	// Should the 20-bit divider width be parameterized?
35	module simpleuart (
36		input clk,
37		input resetn,
38	
39		output ser_tx,
40		input  ser_rx,
41	
42		input  [19:0] cfg_divider,
43	
44		input        b_we,
45		input        b_re,
46		input  [7:0] b_di,
47		output [7:0] b_do,
48		output       b_dv,
49		output       b_busy
50	);
51	
52		reg [3:0] recv_state;
53		reg [19:0] recv_divcnt;
54		reg [7:0] recv_pattern;
55		reg [7:0] recv_buf_data;
56		reg recv_buf_valid;
57	
58		reg [9:0] send_pattern;
59		reg [3:0] send_bitcnt;
60		reg [19:0] send_divcnt;
61		reg send_divcnt_done;
62		reg send_dummy;
63	
64	
65		assign b_busy = b_we && (send_bitcnt || send_dummy);
66		assign b_do = recv_buf_valid ? recv_buf_data : ~0;
67		assign b_dv = recv_buf_valid;
68	
69		always @(posedge clk) begin
70			if (!resetn) begin
71				recv_state <= 0;
72				recv_divcnt <= 0;
73				recv_pattern <= 0;
74				recv_buf_data <= 0;
75				recv_buf_valid <= 0;
76			end else begin
77				recv_divcnt <= recv_divcnt + 1;
78				if (b_re)
79					recv_buf_valid <= 0;
80				case (recv_state)
81					0: begin
82						if (!ser_rx)
83							recv_state <= 1;
84						recv_divcnt <= 0;
85					end
86					1: begin
87						if (2*recv_divcnt > cfg_divider) begin
88							recv_state <= 2;
89							recv_divcnt <= 0;
90						end
91					end
92					10: begin
93						if (recv_divcnt > cfg_divider) begin
94							recv_buf_data <= recv_pattern;
95							recv_buf_valid <= 1;
96							recv_state <= 0;
97						end
98					end
99					default: begin
100						if (recv_divcnt > cfg_divider) begin
101							recv_pattern <= {ser_rx, recv_pattern[7:1]};
102							recv_state <= recv_state + 1;
103							recv_divcnt <= 0;
104						end
105					end
106				endcase
107			end
108		end
109	
110		assign ser_tx = send_pattern[0];
111	
112		always @(posedge clk) begin
113			send_divcnt <= send_divcnt - 1;
114			send_divcnt_done <= send_divcnt==2;
115			if (!resetn) begin
116				send_pattern <= ~0;
117				send_bitcnt <= 0;
118				send_divcnt <= cfg_divider;
119				send_dummy <= 1;
120			end else begin
121				if (send_dummy && !send_bitcnt) begin
122					send_pattern <= ~0;
123					send_bitcnt <= 15;
124					send_divcnt <= cfg_divider;
125					send_dummy <= 0;
126				end else
127				if (b_we && !send_bitcnt) begin
128					send_pattern <= {1'b1, b_di, 1'b0};
129					send_bitcnt <= 10;
130					send_divcnt <= cfg_divider;
131				end else
132				if (send_divcnt_done && send_bitcnt) begin
133					send_pattern <= {1'b1, send_pattern[9:1]};
134					send_bitcnt <= send_bitcnt - 1;
135					send_divcnt <= cfg_divider;
136				end
137			end
138		end
139	endmodule
